import React from 'react';
import Menu from './Menu'; // Assuming Menu.js is the main menu page
import { Box, CssBaseline } from '@mui/material';

function App() {
  return (
    <Box
      display="flex"
      flexDirection="column"
      minHeight="100vh" // Ensures the height of the page covers the full screen
    >
      <CssBaseline /> {/* Ensures proper styling reset */}
      <Menu /> {/* Your main menu content */}
      {/* Footer */}
      <footer
        style={{
          marginTop: 'auto', // This pushes the footer to the bottom
          padding: '20px',
          backgroundColor: '#f1f1f1',
          textAlign: 'center',
        }}
      >
        <p>© 2025 QuickBite. All rights reserved.</p>
      </footer>
    </Box>
  );
}

export default App;
